// Prep top 3 data + build RPC body for Pull enriched T3
const trigger = $('When Executed by Another Workflow').first().json;
const careers = trigger.top_3_careers || [];
const input_careers_text = careers.map(c => ({
  career_title: c.career_title,
  company_size_type: c.company_size_type
}));
return [{ json: {
  top_3_careers: careers,
  rpc_body: JSON.stringify({ input_careers_text })
} }];

// n8n Function Node - Fast reordering for LLM consumption
// No expensive formatting - LLMs handle mixed data formats well

const items = $input.all();

return items.map(item => {
  const data = item.json.career_data || item.json;

  // Simple reordering - no array formatting or parsing
  return {
    json: {
      // === PRIMARY INFORMATION ===
      career_title: data.career_title,
      overview: data.overview,
      salary: data.salary,
      company_size_type: data.company_size_type,

      // === CORE WORK DETAILS ===
      typical_tasks: data.typical_tasks,
      technical_skills: data.technical_skills,
      soft_skills: data.soft_skills,
      education_requirements: data.education_requirements,

      // === WORK ENVIRONMENT ===
      work_schedule: data.work_schedule,
      autonomy_vs_collaboration: data.autonomy_vs_collaboration,
      client_interaction: data.client_interaction,
      colleague_interaction: data.colleague_interaction,

      // === CAREER DEVELOPMENT ===
      career_progression: data.career_progression,
      motivational_factors: data.motivational_factors,
      leadership_challenges: data.leadership_challenges,

      // === METADATA ===
      id: data.id,
      ai_impact_rating: data.ai_impact_rating,
      created_at: data.created_at,
      updated_at: data.updated_at
    }
  };
});

// Get the input text
const fullText = $json.text;
// Get report_id from trigger
const reportId = $('When Executed by Another Workflow').first().json.report_id;

// Subheaders to convert to h5 tags (must match ACTUAL AI output headers)
const CAREER_SUBHEADERS = [
  "Why this role fits you",
  "What you'll actually do",
  "What works for you",
  "The Reality Check",
  "The practical stuff",
  "How AI will impact this role",
  "Alignment with your ambitions"
];


// Function to convert subheaders to h5 tags
function formatSubheaders(content) {
  let formatted = content;

  // Convert ## headers to h5 tags
  formatted = formatted.replace(/^## (.+)$/gm, '<h5>$1</h5>');

  // Also convert bold-only subheaders from the predefined list
  CAREER_SUBHEADERS.forEach(subheader => {
    const regex = new RegExp(`(^|\\n)\\*\\*${subheader}\\*\\*:?\\s*`, 'gi');
    formatted = formatted.replace(regex, `$1<h5>${subheader}</h5>\n\n`);
  });

  // Clean up any leftover markdown bold markers
  formatted = formatted.replace(/\*\*(.*?)\*\*/g, '$1');

  return formatted.trim();
}

// Function to extract career metadata and clean content
function parseCareer(careerText) {
  const lines = careerText.trim().split('\n');
  let title = '';
  let alternateTitles = '';
  let companySizeType = '';
  let score = null;
  let contentStartIndex = 0;

  // Parse first few lines for metadata
  for (let i = 0; i < Math.min(15, lines.length); i++) {
    const line = lines[i].trim();

    // Extract title - ONLY single # (career title), not ## (subheaders)
    if (line.match(/^# [^#]/) ) {
      title = line.replace(/^# /, '').trim();
      contentStartIndex = i + 1;
    } else if (line.match(/^-?\s*Title:/i)) {
      title = line.replace(/^-?\s*Title:\s*/i, '').trim();
      contentStartIndex = Math.max(contentStartIndex, i + 1);
    }

    // Extract alternate titles
    if (line.match(/^\*\*Alternative titles:\*\*/i) || line.match(/^-?\s*\*?Alternate titles:/i)) {
      const altMatch = line.match(/\*\*Alternative titles:\*\* (.+?) \| \*\*At:\*\* (.+)/);
      if (altMatch) {
        alternateTitles = altMatch[1].trim();
        companySizeType = altMatch[2].trim();
        contentStartIndex = Math.max(contentStartIndex, i + 1);
      } else {
        alternateTitles = line
          .replace(/^-?\s*\*?\*?Alternative titles:\*?\*?\s*/i, '')
          .replace(/^-?\s*\*?Alternate titles:\*?\s*/i, '')
          .replace(/\*/g, '')
          .trim();
        contentStartIndex = Math.max(contentStartIndex, i + 1);
      }
    }

    // Extract company size - standalone "At:" line
    if (line.match(/^-?\s*\*?\*?At:\*?\*?\s*/i) && !line.match(/Alternative titles/i)) {
      companySizeType = line
        .replace(/^-?\s*\*?\*?At:\*?\*?\s*/i, '')
        .replace(/\*\*/g, '')
        .trim();
      contentStartIndex = Math.max(contentStartIndex, i + 1);
    }

    // Extract compatibility score
    const scoreMatch = line.match(/\*?\*?Compatibility score:\s*(\d+)\/100\*?\*?/i);
    if (scoreMatch) {
      score = parseInt(scoreMatch[1], 10);
      contentStartIndex = Math.max(contentStartIndex, i + 1);
    }
  }

  // Skip empty lines after metadata
  while (contentStartIndex < lines.length && lines[contentStartIndex].trim() === '') {
    contentStartIndex++;
  }

  // Get remaining content and format subheaders
  const rawContent = lines.slice(contentStartIndex).join('\n').trim();
  const formattedContent = formatSubheaders(rawContent);

  return {
    title: `<h3><strong>${title || 'Career Option'}</strong></h3>`,
    alternate_titles: alternateTitles ? `<strong>Alternate titles:</strong> ${alternateTitles}` : '',
    company_size_type: companySizeType ? `<h4><strong>${companySizeType}</strong></h4>` : '',
    content: formattedContent,
    score: score
  };
}

// Split by separator
const splitCareers = fullText.split('---CAREER_SPLIT---');

// Validate we have 3 parts
if (splitCareers.length !== 3) {
  throw new Error(`Expected 3 careers but found ${splitCareers.length}`);
}

// Parse each career
const career1 = parseCareer(splitCareers[0]);
const career2 = parseCareer(splitCareers[1]);
const career3 = parseCareer(splitCareers[2]);

// Map to structured output with all required fields
return [
  { 
    json: { 
      title: career1.title,
      alternate_titles: career1.alternate_titles,
      company_size_type: career1.company_size_type,
      content: career1.content,
      score: career1.score,
      report_id: reportId,
      section_type: "top_career_1", 
      order_number: 1
    } 
  },
  { 
    json: { 
      title: career2.title,
      alternate_titles: career2.alternate_titles,
      company_size_type: career2.company_size_type,
      content: career2.content,
      score: career2.score,
      report_id: reportId,
      section_type: "top_career_2", 
      order_number: 2
    } 
  },
  { 
    json: { 
      title: career3.title,
      alternate_titles: career3.alternate_titles,
      company_size_type: career3.company_size_type,
      content: career3.content,
      score: career3.score,
      report_id: reportId,
      section_type: "top_career_3", 
      order_number: 3
    } 
  }
];

// Prep runner up data + build RPC body for Pull Runner up
const trigger = $('When Executed by Another Workflow').first().json;
const careers = trigger.runner_up_careers || [];
const input_careers_text = careers.map(c => ({
  career_title: c.career_title,
  company_size_type: c.company_size_type
}));
return [{ json: {
  runner_up: careers,
  rpc_body: JSON.stringify({ input_careers_text })
} }];

// Combine all items into one item
const allItems = $input.all();
const allCareers = allItems.map(item => item.json);

return [{ 
  json: { 
    allCareers: allCareers,
    careerCount: allCareers.length 
  } 
}];

// Parse Runner-Up Careers (Markdown format with CAREER_SPLIT delimiter)
const input = $input.first().json.text;

// Get report_id from the same node that Split Top3 uses
const reportId = $('When Executed by Another Workflow').first().json.report_id;

// Split by the delimiter
const careerBlocks = input.split('---CAREER_SPLIT---').map(block => block.trim()).filter(Boolean);

const results = careerBlocks.map((block, index) => {
  // Extract career title (first # heading, not ## subheaders)
  const titleMatch = block.match(/^# ([^#].+)$/m);
  const career_title = titleMatch ? titleMatch[1].trim() : `Career ${index + 1}`;

  // Extract alternative titles and company size
  const altTitlesMatch = block.match(/\*\*Alternative titles:\*\* (.+?) \| \*\*At:\*\* (.+)/);
  const alternate_titles = altTitlesMatch ? altTitlesMatch[1].trim() : '';
  const company_size_type = altTitlesMatch ? altTitlesMatch[2].trim() : '';

  // Extract compatibility score
  const scoreMatch = block.match(/\*\*Compatibility score: (\d+)\/100\*\*/);
  const score = scoreMatch ? parseInt(scoreMatch[1], 10) : null;

  // Extract sections by headers (aligned with top 3 headers)
  const whyMatch = block.match(/## Why this role fits you\s+([\s\S]*?)(?=## What works for you|$)/);
  const worksMatch = block.match(/## What works for you\s+([\s\S]*?)(?=## The Reality Check|$)/);
  const realityMatch = block.match(/## The Reality Check\s+([\s\S]*?)(?=## The practical stuff|$)/);
  const practicalMatch = block.match(/## The practical stuff\s+([\s\S]*?)(?=## How AI will impact this role|$)/);
  const aiMatch = block.match(/## How AI will impact this role\s+([\s\S]*?)(?=\*\*More details|$)/);

  // Build the full content from sections
  const sections = [
    whyMatch ? `<h5>Why this role fits you</h5>\n\n${whyMatch[1].trim()}` : '',
    worksMatch ? `<h5>What works for you</h5>\n\n${worksMatch[1].trim()}` : '',
    realityMatch ? `<h5>The Reality Check</h5>\n\n${realityMatch[1].trim()}` : '',
    practicalMatch ? `<h5>The practical stuff</h5>\n\n${practicalMatch[1].trim()}` : '',
    aiMatch ? `<h5>How AI will impact this role</h5>\n\n${aiMatch[1].trim()}` : ''
  ].filter(Boolean).join('\n\n');

  // Return one item per career (matches report_sections table structure)
  return {
    json: {
      title: `<h3><strong>${career_title}</strong></h3>`,
      alternate_titles: alternate_titles ? `<strong>Alternate titles:</strong> ${alternate_titles}` : '',
      company_size_type: company_size_type ? `<h4><strong>${company_size_type}</strong></h4>` : '',
      content: sections,
      score: score,
      report_id: reportId,
      section_type: "runner_ups",
      order_number: index + 1
    }
  };
});

return results;

// Prepare data for Dream Job Feasibility prompt
const trigger = $('When Executed by Another Workflow').first().json;
return [{
  json: {
    'Top 3 careers': trigger.top_3_careers_str,
    'Runner up careers': trigger.runner_up_careers_str,
    'Outside box careers': trigger.outside_box_careers_str
  }
}];

// Get report_id from upstream node
const reportId = $('When Executed by Another Workflow').first().json.report_id;

// Get the dream jobs text from the upstream node
const fullText = $json.text;

// Subheaders to convert to h5 tags
const DREAM_JOB_SUBHEADERS = [
  "Overview",
  "Feasibility Rating",
  "Personality Fit",
  "Credentials & Experience",
  "Industry Outlook & Future Trends",
  "Steps for Pursuing This Role"
];

function formatDreamJobContent(content) {
  let formatted = content;

  DREAM_JOB_SUBHEADERS.forEach(subheader => {
    /**
     * Updated Regex:
     * 1. Looks for the subheader at the start of the string or after a newline
     * 2. Allows for optional Markdown stars (**)
     * 3. Allows for an optional colon (:)
     * 4. Ensures it matches the whole line to avoid replacing the word mid-sentence
     */
    const regex = new RegExp(`(^|\\n)\\*?\\*?${subheader}\\*?\\*?:?\\s*(\\n|$)`, 'gi');
    formatted = formatted.replace(regex, `$1<h5>${subheader}</h5>\n\n`);
  });

  // Bold common ratings
  formatted = formatted.replace(/(Low|Moderate|High|Moderate - High)(\s*-)/gi, '<strong>$1</strong>$2');

  // Clean up any leftover markdown bold markers
  formatted = formatted.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');

  return formatted.trim();
}

function parseDreamJob(content) {
  const lines = content.trim().split('\n');
  let title = '';
  let contentStartIndex = 0;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    // Match ## Title or just "Chief Product Officer" if it's the very first line
    if (line.match(/^##\s*.+$/) || (i === 0 && line.length > 0)) {
      title = line.replace(/^##\s*/, '').trim();
      contentStartIndex = i + 1;
      break;
    }
  }

  while (contentStartIndex < lines.length && lines[contentStartIndex].trim() === '') {
    contentStartIndex++;
  }

  const rawContent = lines.slice(contentStartIndex).join('\n').trim();
  const formattedContent = formatDreamJobContent(rawContent);

  return {
    title: title || 'Dream Job',
    content: formattedContent
  };
}

const dreamJobSections = fullText.split('---DREAM_JOB_SPLIT---');
const cleanSections = dreamJobSections.filter(section => section.trim().length > 0);

const records = cleanSections.map((section, index) => {
  const parsed = parseDreamJob(section);

  return {
    json: {
      section_type: "dream_jobs",
      title: `<h3>${parsed.title}</h3>`,
      content: parsed.content,
      report_id: reportId,
      order_number: index + 1
    }
  };
});

return records;

